from src.notifier import send_notification


def run_scheduled_reminders(user_ids: list[int]) -> int:
    """Send scheduled reminder to each user."""
    sent = 0
    for uid in user_ids:
        result = send_notification(uid, "Scheduled reminder")
        if result:
            sent += 1
    return sent

